<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'; import { userApi } from '@/api/services'; import PageState from '@/shared/PageState.vue'; import { date } from '@/shared/format'
const loading=ref(true),error=ref(''),message=ref(''),user=ref<any>({}),sessions=ref<any[]>([]),form=reactive({remind_expire:false,remind_traffic:false,old_password:'',new_password:''});async function load(){loading.value=true;try{[user.value,sessions.value]=await Promise.all([userApi.info(),userApi.sessions().catch(()=>[])]);form.remind_expire=Boolean(user.value.remind_expire);form.remind_traffic=Boolean(user.value.remind_traffic)}catch(e:any){error.value=e.message}finally{loading.value=false}}async function save(){try{await userApi.update({remind_expire:Number(form.remind_expire),remind_traffic:Number(form.remind_traffic)});message.value='设置已保存'}catch(e:any){error.value=e.message}}async function password(){try{await userApi.changePassword({old_password:form.old_password,new_password:form.new_password});message.value='密码已修改';form.old_password=form.new_password=''}catch(e:any){error.value=e.message}}onMounted(load)
</script>
<template><PageState :loading="loading" :error="error" @retry="load"><div class="page-heading"><div><h1>个人中心</h1><p>{{user.email}}</p></div></div><div class="detail-grid"><form class="panel form-panel" @submit.prevent="save"><h2>通知设置</h2><label class="toggle-row"><span><strong>到期邮件提醒</strong><small>订阅即将到期时发送邮件</small></span><input v-model="form.remind_expire" type="checkbox" /></label><label class="toggle-row"><span><strong>流量邮件提醒</strong><small>流量接近用完时发送邮件</small></span><input v-model="form.remind_traffic" type="checkbox" /></label><button class="button primary">保存设置</button></form><form class="panel form-panel" @submit.prevent="password"><h2>修改密码</h2><label>旧密码<input v-model="form.old_password" type="password" required /></label><label>新密码<input v-model="form.new_password" type="password" required /></label><button class="button primary">修改密码</button></form></div><p v-if="message" class="form-message success">{{message}}</p><section class="panel list-panel"><header><h2>最近登录设备</h2></header><article v-for="session in sessions" :key="session.id"><div><strong>{{session.device||session.ip}}</strong><p>{{session.ip}}</p></div><time>{{date(session.last_login_at||session.created_at,true)}}</time></article><div v-if="!sessions.length" class="page-state">暂无活跃设备</div></section></PageState></template>
